// ──────────────────────────────────────────────
// Format the Slack message
// ──────────────────────────────────────────────

const inputItems = $('Match Top Reel Per Client').all();
const itemIndex = $itemIndex;
const data = inputItems[itemIndex].json;

// Claude API response: { content: [{ text: "..." }] }
const claudeResp = $json;
const analysis = (claudeResp.content && claudeResp.content[0] && claudeResp.content[0].text)
  || 'Great engagement this week!';

const fmtNum = (n) => Number(n || 0).toLocaleString('en-US');
const views = fmtNum(data.views);
const likes = fmtNum(data.likes);
const comments = fmtNum(data.comments);
const shares = fmtNum(data.shares);
const platform = (data.platform || 'instagram').charAt(0).toUpperCase() + (data.platform || 'instagram').slice(1);
const videoUrl = data.video_url || '';

const blocks = [
  {
    type: 'header',
    text: {
      type: 'plain_text',
      text: '\ud83d\udd25 Top Reel of the Week',
      emoji: true
    }
  },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `Hey *${data.client_name}* team! Here's your top-performing reel this week:`
    }
  },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*Platform:*\n${platform}` },
      { type: 'mrkdwn', text: `*Views:*\n${views}` },
      { type: 'mrkdwn', text: `*Likes:*\n${likes}` },
      { type: 'mrkdwn', text: `*Comments:*\n${comments}` },
      { type: 'mrkdwn', text: `*Shares:*\n${shares}` }
    ]
  },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*Caption:*\n>${data.caption ? data.caption.substring(0, 200) : 'N/A'}`
    }
  },
  { type: 'divider' },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*Why it performed well:*\n${analysis}`
    }
  }
];

if (videoUrl && videoUrl !== '#') {
  blocks.push({
    type: 'actions',
    elements: [
      {
        type: 'button',
        text: {
          type: 'plain_text',
          text: '\u25b6\ufe0f Watch Reel',
          emoji: true
        },
        url: videoUrl,
        action_id: 'watch_reel'
      }
    ]
  });
}

return {
  json: {
    slack_channel_id: data.slack_channel_id,
    client_name: data.client_name,
    text: `Top reel of the week for ${data.client_name}: ${views} views`,
    blocks: JSON.stringify(blocks)
  }
};
